  const ayahs: AyahProps[] = [
    { ayahId: 61, surahNumber: 2, pageNumber: 9, isComplete: true, continuesFromPrev: true, textData: "لَن نُّومِنَ لَكَ حَتَّيٰ نَرَي ۰للَّهَ جَهْرَةً فَأَخَذَتْكُمُ ۴لصَّـٰعِقَةُ وَأَنتُمْ تَنظُرُونَؐ" },
    { ayahId: 62, surahNumber: 2, pageNumber: 9, isComplete: true, continuesFromPrev: false, textData: "ثُمَّ بَعَثْنَــٰكُم مِّنۢ بَعْدِ مَوْتِكُمْ لَعَلَّكُمْ تَشْكُرُونَؐ" },
    { ayahId: 63, surahNumber: 2, pageNumber: 9, isComplete: true, continuesFromPrev: false, textData: "وَظَلَّلْنَا عَلَيْكُمُ ۴لْغَمَـٰمَ وَأَنزَلْنَا عَلَيْكُمُ ۴لْمَنَّ وَالسَّلْوۭيٰؐ كُلُواْ مِن طَيِّبَــٰــتِ مَا رَزَقْنَـٰكُمْؐ وَمَا ظَلَمُونَاؐ وَچَكِــن كَانُوٓاْ أَنفُسَهُمْ يَظْلِمُونَؐ" },
    { ayahId: 64, surahNumber: 2, pageNumber: 9, isComplete: true, continuesFromPrev: false, textData: "وَإِذْ قُلْنَا ۸دْخُلُواْ هَـٰذِهِ ۱لْقَرْيَةَ فَكُلُواْ مِنْهَا حَيْثُ شِيؔتُمْ رَغَداً وَادْخُلُواْ ۴لْبَابببَ سُجَّداً وَقُولُواْ حِطَّةٌ يُغْفَرْ لَكُمْ خَطَـٰيۭـٰكُمْؐ وَسَنَزۣيدُ ۴ڤْمُحْسِنِينَؐ" },
    { ayahId: 65, surahNumber: 2, pageNumber: 9, isComplete: true, continuesFromPrev: false, textData: "فَبَدَّلَ ۰لذِينَ ظَلَمُواْ قَوْلٗا غَيْرَ ۰ﻟ﮲ قِيلَ لَهُمْ فَأَنزَلْنَا عَلَي ۰لذِينَ ظَلَمُواْ رۣجْزاً مِّنَ ۰لسَّمَآءِ بِمَا كَانُواْ يَفْسُقُونَؐ ©" },
    { ayahId: 66, surahNumber: 2, pageNumber: 9, isComplete: true, continuesFromPrev: false, textData: "وَإِذِ 'سْتَسْقۭيٰ مُوسۭيٰ لِقَوْمِهِ” فَقُلْنَا \"ضْرۣب بِّعَصَاكَ ۰لْحَجَـرَؐ فَانفَجَرَتْ مِنْهُ èثْنَتَا عَشْرَةَ عَيْناًؐ قَدْ عَلِمَ كُلُّ ٱُنَاسٍ مَّشْرَبَهُمْؐ كُلُواْ وَاشْرَبُواْ مِن رّۣزْقِ ۱للَّهِؐ وَلاَ تَعْثَوْاْ فِى ۱لاَرْضِ مُفْسِدِينَؐ" },
    { ayahId: 67, surahNumber: 2, pageNumber: 9, isComplete: false, continuesFromPrev: false, textData: "وَإِذْ قُلْتُمْ يَـٰمُوسۭيٰ لَن نَّصْبِرَ عَلَيٰ طَعَامٍ وَ؛حِدٍ فَادْعُ لَنَا رَبَّكَ يُخْرۣجْ لَنَا مِمَّا تُنۢبِــتُ ۴لاَرْضُ مِنۢ بَقْلِهَا وَقِثَّآئِهَا وَفُومِهَا وَعَدَسِهَا وَبَصَلِهَاؐ قَالَ أَتَسْتَبْدِلُونَ" }
  ];

